using Microsoft.Extensions.Logging;

public sealed class AuthHandler(ILogger<AuthHandler> logger)
{
    public void Reject(string authorizationHeader)
    {
        logger.LogWarning("Rejected authorization header {AuthorizationHeader}", authorizationHeader);
    }
}

using Microsoft.Extensions.Logging;

public sealed class AuthHandler(ILogger<AuthHandler> logger)
{
    public void Reject(string userId)
    {
        logger.LogWarning("Rejected authentication for user {UserId}", userId);
    }
}
